_____javascript
const { latitude, longitude } = { latitude: 49.393813868077764, longitude: 17.22388380435019 };
const urls = [
  `https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current=temperature_2m,apparent_temperature,weather_code,wind_speed_10m,precipitation,rain,snowfall&timezone=auto`,
  `https://api.met.no/weatherapi/locationforecast/2.0/compact?lat=${latitude}&lon=${longitude}`
];

function codeToText(code) {
  const map = {
    0: "clear sky",
    1: "mainly clear",
    2: "partly cloudy",
    3: "overcast",
    45: "fog",
    48: "depositing rime fog",
    51: "light drizzle",
    53: "moderate drizzle",
    55: "dense drizzle",
    61: "slight rain",
    63: "moderate rain",
    65: "heavy rain",
    71: "slight snow",
    73: "moderate snow",
    75: "heavy snow",
    80: "rain showers",
    81: "moderate rain showers",
    82: "violent rain showers",
    95: "thunderstorm"
  };
  return map[code] || `weather code ${code}`;
}

for (const url of urls) {
  try {
    const res = await fetch(url, { headers: { "accept": "application/json" } });
    if (!res.ok) continue;
    const data = await res.json();

    if (data?.current) {
      return {
        source: "open-meteo",
        temperature: data.current.temperature_2m,
        apparent: data.current.apparent_temperature,
        wind: data.current.wind_speed_10m,
        description: codeToText(data.current.weather_code),
        precipitation: data.current.precipitation
      };
    }

    const timeseries = data?.properties?.timeseries?.[0];
    const instant = timeseries?.data?.instant?.details;
    const next1h = timeseries?.data?.next_1_hours?.summary?.symbol_code;
    if (instant) {
      return {
        source: "met.no",
        temperature: instant.air_temperature,
        wind: instant.wind_speed,
        description: next1h || "weather available"
      };
    }
  } catch (e) {}
}

return { error: "Could not fetch weather data" }

